/**
 * Map an AgentPhase kind to a single-char status glyph.
 */
// @kern-source: agent:22
function phaseGlyph(phase: string): string {
  if (phase === 'running') return '\u25cf'; // ●
  if (phase === 'awaiting_approval') return '\u25c6'; // ◆
  if (phase === 'completed') return '\u2713'; // ✓
  if (phase === 'failed') return '\u2717'; // ✗
  if (phase === 'cancelled') return '\u25ce'; // ◎
  return '\u00b7'; // ·
}

/**
 * Terminal color for a phase glyph.
 */
// @kern-source: agent:33
function phaseColor(phase: string): string {
  if (phase === 'running') {
    return '#fbbf24';
  }
  if (phase === 'awaiting_approval') {
    return '#60a5fa';
  }
  if (phase === 'completed') {
    return '#22c55e';
  }
  if (phase === 'failed') {
    return '#ef4444';
  }
  if (phase === 'cancelled') {
    return '#9ca3af';
  }
  return '#6b7280';
}

/**
 * Unicode block-bar string. pct in [0,1], width is cell count.
 */
// @kern-source: agent:48
function progressBar(pct: number, width: number): string {
  const p = Math.max(0, Math.min(1, pct));
  const filled = Math.round(p * width);
  const empty = width - filled;
  return '█'.repeat(filled) + '░'.repeat(empty);
}

/**
 * Human-readable elapsed time (e.g. '42s', '3m12s', '1h04m').
 */
// @kern-source: agent:56
function formatElapsed(ms: number): string {
  const secs = Math.floor(ms / 1000);
  if (secs < 60) {
    return `${secs}s`;
  }
  const mins = Math.floor(secs / 60);
  const rem = secs % 60;
  if (mins < 60) {
    return `${mins}m${rem.toString().padStart(2, '0')}s`;
  }
  const hours = Math.floor(mins / 60);
  const mrem = mins % 60;
  return `${hours}h${mrem.toString().padStart(2, '0')}m`;
}

/**
 * Render token count as 1.2k, 45k, 1.4M.
 */
// @kern-source: agent:70
function formatTokens(tokens: number): string {
  if (tokens < 1000) {
    return `${tokens} tok`;
  }
  if (tokens < 1_000_000) {
    return `${(tokens / 1000).toFixed(1)}k tok`;
  }
  return `${(tokens / 1_000_000).toFixed(2)}M tok`;
}
